VALUES
  ('judicial-d35ec6db-moex-00057', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-2909f946', 'sub-judicial-d35ec6db-03', NULL, 'essay', '甲涉犯刑法第 328 條第 3項強盜致重傷罪嫌，檢察官乙偵查終結後向管
轄法院提起強盜罪之公訴，嗣後，檢察官丙亦向同一管轄法院，對甲提
起過失重傷罪之公訴；惟檢察官丙發覺同一案件已提起公訴後，依照刑
事訴訟法第 269條第 1項規定，於第一審辯論終結前，以「雙重起訴」
為由，撤回過失重傷罪之公訴。試論管轄法院應如何裁判？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "5af716a5f6fa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00058', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'essay', '甲最近想換工作，甲的表哥乙得知後，想到自己的高中好友丙開設好幾
家機車行，可以請丙安排甲到機車行上班，於是乙跟甲討論此事，甲跟
乙說「請表哥幫我安排看看吧」，乙是商務人士，要甲授與代理權給自己，
甲同意。其後乙在同學會遇見丙，談到自己的表弟甲想到丙的機車行上
班當學徒，乖乖聽丙的話工作，且自己是甲的代理人一事，丙一聽爽快
答應，但丙內心根本不把此事當一回事，認為答應此事只是優雅的社交
辭令而隨口答應。然而乙不知道丙有著隨便答應別人，但事後做不到的
習性，喜孜孜地把好消息告訴甲，甲因此辭掉了原本的工作，自己到丙
的機車行報到。丙見到甲來訪，十分詫異，跟甲說自己當初答應只是朋
友間的玩笑話，自己的機車行根本不缺人，沒有要聘用甲的意思。請問
丙、甲之間的僱傭契約成立嗎？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00059', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'essay', '甲男最近迷戀上線上主播乙女，花大錢後取得乙女通訊軟體line的帳號，
隨著交談熱烈，兩人在 line上確認男女朋友關係。乙女稱自己受線上直
播平台老闆控制，絕對不能私下和甲男見面，否則必須償付天價違約金，
而且老闆同時控制乙女的 line和人身自由，如果要繼續聊天、發送照片，
必須每個月匯款6 萬元到某銀行帳戶（其後經查是乙女的帳戶），乙女才
能和心愛的男友甲在 line上繼續談情說愛、將來結婚共創未來。甲不疑
有他，陸續匯出多筆款項。實則，乙女的直播平台本身做正當生意，選
任監督並無疏失，但乙女認為能撈就撈，乙女還聘用了丙男假冒乙女，
幫她在 line上面與多位粉絲談情說愛，並用同樣的話術從數位粉絲上取
得大筆金錢。請問若甲男事後知情，得做如何主張？（25分）
20320
20420', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00060', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '法人若有數名監察人，關於監察權之行使，應依下列何種方式為之？', '["除章程另有規定外，各監察人均得單獨行使", "除章程另有規定外，應由全體監察人過半數之同意行使", "各監察人單獨行使，章程不得另外限制", "全體監察人過半數之同意行使，章程不得另外限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00061', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '依民法規定設立之社團，關於其社員之退社或開除，下列敘述何者錯誤？', '["得自由退社", "得隨時不具理由開除社員", "社員，對於其退社或開除以前應分擔之出資，仍負清償之義務", "開除社員，原則上經總會決議，以出席社員過半數決之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00062', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '依實務見解，下列關於物之敘述，何者錯誤？', '["凡繼續附著於土地之輕便軌道，均認為不動產", "定著物在未完成以前，應認為動產", "四壁及底面由水泥磚塊砌成之水池，應認其為土地之成分", "變電室及守衛室為工廠之從物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00063', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於動產、不動產之敘述，何者錯誤？', '["菜園上之蔬菜，與土地未分離前屬於獨立之不動產", "廟前之牌樓屬於不動產", "新屋建築雖已大致完成，但屋頂因材料短缺，尚有部分未完成，惟大部分樓層皆已可使用，即 屬於不動產", "關渡大橋屬於地上定著物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00064', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲擁有市價新臺幣(下同)500萬元之超跑A車，乙極為喜歡，故向甲以600萬元高價購買，當場 甲就將A車交付於乙，並為讓與合意，但甲、乙均因忙碌，故未至監理機關辦理過戶，乙也未給 付價金600萬元。嗣甲缺錢，遂將A車再以700萬元高價出售於丙，丙當場交付價金700萬元， 甲並至監理機關辦理A車過戶於丙。下列敘述何者正確？', '["甲已將A車出售於乙後，不得再出售於丙", "丙為監理機關登記之A車車主，故丙取得A車之所有權", "乙向甲購買A車，但未交付價金，故乙未取得A車所有權", "乙取得A車所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00065', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何者組合非屬主物與從物之關係？', '["電視機及其遙控器", "筆記型電腦及其充電器", "汽車及其備胎", "果園及其果樹"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00066', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲對乙有新臺幣100萬元之債權，甲將該債權讓與丙。下列敘述何者錯誤?', '["附著於該債權之擔保，亦隨之移轉於丙", "甲、丙間之債權讓與契約，須乙之同意，始生效力", "丙將債權讓與通知乙時，債權讓與契約即可對乙生效", "乙受債權讓與通知時，原則上可對抗甲之事由，皆得以之對抗丙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
